oxy_webhelp_navlinks = {"tocId-d23535e20031":{"topics":[{"title":"Hyper-V virtual machines","shortdesc":"<p class=\"shortdesc\">A Rubrik cluster provides data management and protection for virtual machines that are       deployed in a Microsoft Hyper-V environment. The Rubrik cluster can manage and protect virtual       machines in an environment with multiple Hyper-V servers and virtual machines.<\/p>","href":"saas\/hyper_v\/hyperv_virtual_machines.html","attributes":{"data-id":"hyperv_virtual_machines"},"menu":{"hasChildren":false},"tocID":"hyperv_virtual_machines-d23535e20032","next":"hyperv_virtual_machines-d23535e20032"},{"title":"File systems","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> provides management and protection of file system data on supported Linux,         Unix, and Windows hosts through filesets.<\/p>","href":"saas\/fs_filesystems.html","attributes":{"data-id":"fs_filesystems"},"menu":{"hasChildren":false},"tocID":"fs_filesystems-d23535e20902","next":"fs_filesystems-d23535e20902"},{"title":"Microsoft Exchange Server","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">Rubrik Security Cloud<\/span> provides protection for Microsoft Exchange         Servers.<\/p>","href":"saas\/ms_exchange_server.html","attributes":{"data-id":"ms_exchange_server"},"menu":{"hasChildren":false},"tocID":"ms_exchange_server-d23535e21528","next":"ms_exchange_server-d23535e21528"},{"title":"AHV virtual machines","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> provides data management and protection for virtual machines         deployed in a Nutanix Acropolis environment.<\/p>","href":"nutanix_ahv\/ahv_virtual_machines.html","attributes":{"data-id":"rsc_ahv_virtual_machines"},"menu":{"hasChildren":false},"tocID":"rsc_ahv_virtual_machines-d23535e21741","next":"rsc_ahv_virtual_machines-d23535e21741"},{"title":"vSphere virtual machines","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">Rubrik Security Cloud<\/span> provides data management and SLA Domain protection for         vSphere virtual machines, including vSphere VM templates that are managed either through a         VMware vSphere environment or a content library.<\/p>","href":"saas\/vs_virtual_machines.html","attributes":{"data-id":"vs_virtual_machines"},"menu":{"hasChildren":false},"tocID":"vs_virtual_machines-d23535e22585","next":"vs_virtual_machines-d23535e22585"},{"title":"VMware Cloud","shortdesc":"<p class=\"shortdesc\">A Rubrik Cloud Cluster effectively protects virtual machines deployed on VMware Cloud         on AWS, Microsoft Azure VMware Solution, and Google Cloud VMware Engine.<\/p>","href":"vmware_cloud\/vmware_cloud.html","attributes":{"data-id":"vmware_cloud"},"menu":{"hasChildren":false},"tocID":"vmware_cloud-d23535e23963","next":"vmware_cloud-d23535e23963"},{"title":"VMware Cloud Director vApps","shortdesc":"<p class=\"shortdesc\">The Rubrik cluster provides SLA Domain protection and data management for VMware Cloud       Director vApps.<\/p>","href":"vcd\/vmware_cloud_director_vapps.html","attributes":{"data-id":"vmware_cloud_director_vapps"},"menu":{"hasChildren":false},"tocID":"vmware_cloud_director_vapps-d23535e24051","next":"vmware_cloud_director_vapps-d23535e24051"},{"title":"Windows volume groups","shortdesc":"<p class=\"shortdesc\">A volume group is a Rubrik workload comprised of at least one data storage volume on         a Windows host.<\/p>","href":"saas\/windows_volume_groups.html","attributes":{"data-id":"windows_volume_groups"},"menu":{"hasChildren":false},"tocID":"windows_volume_groups-d23535e24392","next":"windows_volume_groups-d23535e24392"}]}};